mapper.select:
SELECT 
    id, level, module, message, stack_trace, ip, user_id, request_id, log_time
FROM system_log


        AND level = #{request.level}


        AND module LIKE CONCAT('%', #{request.module}, '%')


        AND log_time >= #{request.startTime}


        AND log_time <= #{request.endTime}


ORDER BY log_time DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM system_log


        AND level = #{request.level}


        AND module LIKE CONCAT('%', #{request.module}, '%')


        AND log_time >= #{request.startTime}


        AND log_time <= #{request.endTime}
